  ('optometrist-moex-02777', 'optometrist', 'optometrist-moex-107-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '屈光不正患者戴上 +1.00 DS 的球面眼鏡後，測得其遠點為眼後50 cm，該患者原屈光不正度數為？', '["-1.00 D", "-2.00 D", "+3.00 D", "+2.00 D"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "4027944ff457", "answer_pdf_sha1": "0225acf7b780", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02778', 'optometrist', 'optometrist-moex-107-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '無特殊病變之新生兒出生的屈光狀態（不考慮調節力），下列何者最常見？', '["-5 D～-6 D近視", "+6 D～+8 D遠視", "-1 D～-2 D近視", "+2 D～+4 D遠視"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "4027944ff457", "answer_pdf_sha1": "0225acf7b780", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02779', 'optometrist', 'optometrist-moex-107-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關夜間近視的敘述，下列何者錯誤？', '["低光源環境下近視度數的增加稱為夜間近視", "夜間增加的近視度數約為0.5 D到1.0 D", "可能原因是眼睛在夜間最敏感的光波長較白天長，造成焦點前移，產生近視", "可能原因是夜間光線不足造成調節力增加，產生調節性近視"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "4027944ff457", "answer_pdf_sha1": "0225acf7b780", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02780', 'optometrist', 'optometrist-moex-107-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '一平行光通過散光鏡片會形成兩條焦線，若前焦線是垂直線，則此鏡片屈光力之敘述，下列何者正確？', '["水平方向的屈光力最強", "垂直方向的屈光力最強", "水平方向是最強屈光力的軸向", "垂直方向是最弱屈光力的軸向"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "4027944ff457", "answer_pdf_sha1": "0225acf7b780", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02781', 'optometrist', 'optometrist-moex-107-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '下列有關散光的敘述，何者錯誤？', '["散光患者為求看清楚，不斷使用視力調節，容易產生調節性眼力疲勞（accommodative asthenopia）、神 經性眼力疲勞（nervous asthenopia）、肌性眼力疲勞（muscular asthenopia）等", "角膜鏡（keratoscope）、散光盤（astigmatic dial）、傑克森交叉圓柱鏡（Jackson cross cylinder lens, JCC） 都是檢測散光的工具", "普通眼鏡之圓柱鏡即可完全矯正不規則散光", "學齡前的兒童若有高度散光，會有歪頭、瞇眼等習慣，也有可能產生弱視"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "4027944ff457", "answer_pdf_sha1": "0225acf7b780", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02782', 'optometrist', 'optometrist-moex-107-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '對比敏感度測試流程（contrast sensitivity test procedure）中，下列何種測試流程會低估受測者的對比敏感 度臨界值？', '["上升極限法（ascending limits）", "下降極限法（descending limits）", "階梯平均法（staircase）", "水平極限法（horizontal limits）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "4027944ff457", "answer_pdf_sha1": "0225acf7b780", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
